import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is profit margin?", a: "Profit margin is the percentage of revenue left after subtracting costs. It shows how much profit a business keeps from each sale." },
  { q: "What is the difference between margin and markup?", a: "Margin compares profit to selling price, while markup compares profit to cost. The same sale has a higher markup percentage than margin percentage." },
  { q: "How do you calculate gross margin?", a: "Gross margin equals gross profit divided by revenue, multiplied by 100. Gross profit is revenue minus cost." },
  { q: "What is a good profit margin for a business?", a: "A good profit margin depends on the industry, business model, overhead, and growth stage. Low-volume businesses often need higher margins than high-volume retailers." },
  { q: "How do you calculate net profit margin?", a: "Net profit margin equals net profit divided by revenue, multiplied by 100. Net profit includes operating expenses, taxes, and other costs." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

export default function MarginCalculator() {
  useCurrencyVersion();
  const [mode, setMode] = useState("margin");
  const [cost, setCost] = useState(60);
  const [revenue, setRevenue] = useState(100);
  const [desiredMargin, setDesiredMargin] = useState(40);
  const [expenses, setExpenses] = useState(10);

  const result = useMemo(() => {
    let c = cost;
    let r = revenue;
    if (mode === "price") r = desiredMargin >= 100 ? 0 : c / (1 - desiredMargin / 100);
    if (mode === "cost") c = r * (1 - desiredMargin / 100);
    const grossProfit = r - c;
    const grossMargin = r ? grossProfit / r * 100 : 0;
    const markup = c ? grossProfit / c * 100 : 0;
    const netProfit = grossProfit - expenses;
    const netMargin = r ? netProfit / r * 100 : 0;
    return { cost: c, revenue: r, grossProfit, grossMargin, markup, netProfit, netMargin };
  }, [mode, cost, revenue, desiredMargin, expenses]);

  const margins = [10, 20, 30, 40, 50, 60];

  return (
    <>
      <SEOHead title="Free Margin Calculator Online - Calculate Profit Margin and Markup Instantly | CalcHive" description="Free online margin calculator. Calculate gross profit margin, selling price from cost and margin, and understand markup vs margin instantly. 100% free, no signup required." canonical="/margin-calculator" keywords="free margin calculator, profit margin calculator free online, gross margin calculator free, markup vs margin calculator free, calculate selling price from margin free" category="Financial Calculators" breadcrumbName="Free Margin Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Margin Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate profit margin, selling price, cost, gross margin, net margin, and markup.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label className="text-sm font-semibold text-foreground block mb-2">Mode</label><select value={mode} onChange={(e) => setMode(e.target.value)} className={inputClass}><option value="margin">Margin from cost and revenue</option><option value="price">Selling price from cost and margin</option><option value="cost">Cost from selling price and margin</option></select></div>
            <div><label className="text-sm font-semibold text-foreground block mb-2">Other expenses</label><input type="number" value={expenses} onChange={(e) => setExpenses(Number(e.target.value))} className={inputClass} /></div>
            {mode !== "cost" && <div><label className="text-sm font-semibold text-foreground block mb-2">Cost</label><input type="number" value={cost} onChange={(e) => setCost(Number(e.target.value))} className={inputClass} /></div>}
            {mode !== "price" && <div><label className="text-sm font-semibold text-foreground block mb-2">Selling price / revenue</label><input type="number" value={revenue} onChange={(e) => setRevenue(Number(e.target.value))} className={inputClass} /></div>}
            {mode !== "margin" && <div><label className="text-sm font-semibold text-foreground block mb-2">Desired margin (%)</label><input type="number" value={desiredMargin} onChange={(e) => setDesiredMargin(Number(e.target.value))} className={inputClass} /></div>}
          </div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Gross Margin</p><p className="text-5xl sm:text-6xl font-black text-white">{pct(result.grossMargin)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Gross profit</p><p className="text-lg font-extrabold text-foreground">{money(result.grossProfit)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Markup</p><p className="text-lg font-extrabold text-foreground">{pct(result.markup)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Net margin</p><p className="text-lg font-extrabold text-foreground">{pct(result.netMargin)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Profit Margin for Free</h2><p className="text-muted-foreground leading-relaxed">Profit margin equals profit divided by selling price. Use this margin calculator to solve margin, price, or cost instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">What Is the Difference Between Margin and Markup</h2>
          <div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Margin vs Markup Reference Table</caption><thead className="bg-muted/60"><tr>{["Cost", "Selling Price", "Gross Profit", "Margin %", "Markup %"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{margins.map((m) => { const c = 100; const s = c / (1 - m / 100); const p = s - c; return <tr key={m}><td className="py-2.5 px-3">{money(c)}</td><td className="py-2.5 px-3">{money(s)}</td><td className="py-2.5 px-3">{money(p)}</td><td className="py-2.5 px-3">{m}%</td><td className="py-2.5 px-3">{pct(p / c * 100)}</td></tr>; })}</tbody></table></div>
          <h2 className="text-2xl font-bold text-foreground">Free Business Profit Margin Tool for Everyone</h2><p className="text-muted-foreground leading-relaxed">Use it for product pricing, ecommerce planning, client quotes, and quick markup vs margin checks.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/margin-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


